--
-- Create or alter function [SJob].[tvf_Assets_PossibleDuplicates]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Assets_PossibleDuplicates]
	(
		@UserId INT
	)
RETURNS TABLE
--WITH SCHEMABINDING
AS
RETURN SELECT	apd.ID,
		apd.RowStatus,
		apd.RowVersion,
		apd.Guid,
		a.AssetNumber,
		a.FormattedAddressComma,
		a.Latitude,
		a.Longitude,
		a2.Guid AS DupGuid,
		a2.AssetNumber AS DupAssetNumber,
		a2.FormattedAddressComma AS DupFormattedAddressComma,
		a2.Latitude AS DupLatitude,
		a2.Longitude AS DupLongitude
FROM	SJob.AssetPossibleDuplicates AS apd	
JOIN	SJob.Assets AS a ON (a.Id = apd.SourceAssetID)
JOIN	SJob.Assets AS a2 ON (a2.ID = apd.TargetAssetID)
WHERE	(EXISTS
				(
						SELECT
								1
						FROM
								SCore.ObjectSecurityForUser_CanRead(a.Guid, @UserId) oscr
				)
			)
	AND	(EXISTS
				(
						SELECT
								1
						FROM
								SCore.ObjectSecurityForUser_CanRead(a2.Guid, @UserId) oscr
				)
			)
	AND	(apd.IsDifferent = 0)
	AND	(apd.IsDuplicate = 0)
	
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SJob].[AssetPossibleDuplicates_Find]
--
GO
CREATE OR ALTER PROCEDURE [SJob].[AssetPossibleDuplicates_Find]
AS
BEGIN
	DECLARE	@PossibleDuplicates TABLE 
	(
		Guid UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID(),
		SourceAssetID INT NOT NULL, 
		TargetAssetID INT NOT NULL
	)

	INSERT INTO @PossibleDuplicates
		 (Guid, SourceAssetID, TargetAssetID)
	SELECT	NEWID (),			-- Guid - uniqueidentifier
			a.ID,				-- SourceAssetID - int
			PossibleMatches.ID -- TargetAssetID - int
	FROM	SJob.Assets AS a
	CROSS APPLY
			(
				SELECT	a2.ID
				FROM	SJob.Assets AS a2
				WHERE	(a.ID <> a2.ID)
					AND (EXISTS
					(
						SELECT	1
						FROM	SJob.Assets AS a3
						WHERE	(a2.ID			   = a3.ID)
							AND (a3.AssetNumber	   > a.AssetNumber)
							AND (a3.RowStatus NOT IN (0, 254))
							AND
							  (
								  (
									  (a.Postcode  = a3.Postcode)
								  AND (a.Postcode  <> N'')
								  AND (a3.Postcode <> N'')
								  AND (a.Number	   = a3.Number)
								  AND (a.Number	   <> N'')
								  AND (a3.Number   <> N'')
								  )
							   OR
								(
									(a.Latitude	   = a3.Latitude)
								AND (a.Longitude   = a3.Longitude)
								AND (a3.Latitude   <> 0)
								AND (a.Latitude	   <> 0)
								)
							  )
					)
						)
			)			AS PossibleMatches
	WHERE	(PossibleMatches.ID IS NOT NULL)
		AND	(NOT EXISTS
		(
			SELECT	1
			FROM	SJob.AssetPossibleDuplicates AS apd
			WHERE	(apd.SourceAssetID = a.ID)
				AND	(apd.TargetAssetID = PossibleMatches.ID)
		)
			)

	DECLARE	@GuidList SCore.GuidUniqueList

	INSERT	@GuidList
		 (GuidValue)
	SELECT	Guid
	FROM	@PossibleDuplicates AS pd


	DECLARE @IsInsert BIT;
	EXEC SCore.DataObjectBulkUpsert @GuidList = @GuidList,				-- GuidUniqueList
									@SchemeName = N'SJob',				-- nvarchar(255)
									@ObjectName = N'AssetPossibleDuplicates',				-- nvarchar(255)
									@IncludeDefaultSecurity = 0,	-- bit
									@IsInsert = @IsInsert OUTPUT	-- bit
	

	INSERT INTO SJob.AssetPossibleDuplicates
		 (RowStatus, Guid, SourceAssetID, TargetAssetID, IsDifferent, IsDuplicate)
	SELECT	1,					-- RowStatus - tinyint
			pd.Guid,			-- Guid - uniqueidentifier
			pd.TargetAssetID,				-- SourceAssetID - int
			pd.SourceAssetID, -- TargetAssetID - int
			0,					-- IsDifferent - bit
			0					-- IsComplete - bit
	FROM	@PossibleDuplicates AS pd

END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SJob].[AssetPossibleDuplicatesUpsert]
--
GO





CREATE OR ALTER PROCEDURE [SJob].[AssetPossibleDuplicatesUpsert]
	(	@IsDifferent BIT,
		@IsDuplicate BIT,
		@Guid UNIQUEIDENTIFIER
	)
AS
BEGIN
	DECLARE @SourceAssetId INT,
			@TargetAssetId INT,
			@CreatedByUserId INT,
			@SourceDifferent BIT,
			@SourceDuplicate BIT;

	SELECT @CreatedByUserId = SCore.GetCurrentUserId()

	SELECT	@SourceAssetId = apd.SourceAssetId,
			@TargetAssetId = apd.TargetAssetID,
			@SourceDifferent = apd.IsDifferent,
			@SourceDuplicate = apd.IsDuplicate
	FROM	SJob.AssetPossibleDuplicates AS apd
	WHERE	(apd.Guid = @Guid)

	IF (@SourceDuplicate = 1) 
	BEGIN 
		-- Nothing to do
		RETURN
	END

	IF (@IsDifferent = 1 AND @IsDuplicate = 1)
	BEGIN 
		;THROW 60000, N'A suggestion cannot be different and a duplicate.', 1
	END

	UPDATE	SJob.AssetPossibleDuplicates
	SET		IsDifferent = @IsDifferent,
			IsDuplicate = @IsDuplicate
	WHERE	(Guid = @Guid)

	IF (@IsDuplicate = 1) 
	BEGIN 
		/* Create the merge batch record. */
		DECLARE @IsInsert BIT
		DECLARE	@MergeBatchGuid UNIQUEIDENTIFIER = NEWID()
		EXEC SCore.UpsertDataObject @Guid = @MergeBatchGuid,					-- uniqueidentifier
								@IncludeDefaultSecurity = 0,
								@SchemeName = N'SJob',				-- nvarchar(255)
								@ObjectName = N'AssetMergeBatch',				-- nvarchar(255)
								@IsInsert = @IsInsert OUTPUT	-- bit

		IF (@IsInsert = 1)
		BEGIN
			INSERT	SJob.AssetMergeBatch
				 (RowStatus, Guid, SourceAssetId, TargetAssetId, CreatedByUserId, CheckedByUserId, IsComplete)
			VALUES
				 (
					 1,					-- RowStatus - tinyint
					 @MergeBatchGuid,				-- Guid - uniqueidentifier
					 @SourceAssetId,	-- SourceAssetId - int
					 @TargetAssetId,	-- TargetAssetId - int
					 @CreatedByUserId,	-- CreatedByUserId - int
					 ((-1)),	-- CheckedByUserId - int
					 0					-- IsComplete - bit
				 );

		END;
	END;

END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

