--
-- Create or alter procedure [SJob].[MergeAssets]
--
GO
CREATE OR ALTER PROCEDURE [SJob].[MergeAssets]
(
	@FromAssetGuid UNIQUEIDENTIFIER,
	@ToAssetGuid UNIQUEIDENTIFIER
)
AS
BEGIN 
	DECLARE	@FromAssetID INT,
			@ToAssetID INT

	SELECT	@FromAssetID = ID
	FROM	SJob.Assets
	WHERE	(guid = @FromAssetGuid)

	SELECT	@ToAssetID = ID 
	FROM	SJob.Assets
	WHERE	(Guid = @ToAssetGuid)

	UPDATE	SJob.Assets
	SET		ParentAssetID = @ToAssetID
	WHERE	ParentAssetID = @FromAssetID

	UPDATE	SJob.Jobs
	SET		UprnID = @ToAssetID
	WHERE	(UprnID = @FromAssetID)

	UPDATE	SSop.Enquiries 
	SET		PropertyId = @ToAssetID
	WHERE	(PropertyId = @FromAssetID)

	UPDATE	SSop.Quotes 
	SET		UprnId = @ToAssetID
	WHERE	(UprnId = @FromAssetID)

	UPDATE	SJob.Assets
	SET		RowStatus = 254
	WHERE	(Guid = @FromAssetGuid)
		
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SJob].[AssetMergeBatchUpsert]
--
GO




CREATE OR ALTER PROCEDURE [SJob].[AssetMergeBatchUpsert]
	(	@SourceAssetGuid UNIQUEIDENTIFIER,
		@TargetAssetGuid UNIQUEIDENTIFIER,
		@CreatedByUserGuid UNIQUEIDENTIFIER,
		@CheckedByUserGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER
	)
AS
BEGIN
	DECLARE @SourceAssetId INT,
			@TargetAssetId INT,
			@CreatedByUserId INT,
			@CheckedByUserId INT;

	SELECT	@SourceAssetId = ID
	FROM	SJob.Assets
	WHERE	(Guid = @SourceAssetGuid);

	SELECT	@TargetAssetId = ID
	FROM	Sjob.Assets
	WHERE	(Guid = @TargetAssetGuid);

	SELECT	@CreatedByUserId = ID
	FROM	SCore.Identities
	WHERE	(Guid = @CreatedByUserGuid);

	SELECT	@CheckedByUserId = ID
	FROM	SCore.Identities
	WHERE	(Guid = @CheckedByUserGuid);

	DECLARE @IsInsert BIT
    EXEC SCore.UpsertDataObject @Guid = @Guid,					-- uniqueidentifier
							@IncludeDefaultSecurity = 0,
							@SchemeName = N'SJob',				-- nvarchar(255)
							@ObjectName = N'AssetMergeBatch',				-- nvarchar(255)
							@IsInsert = @IsInsert OUTPUT	-- bit

    IF (@IsInsert = 1)
    BEGIN
		INSERT	SJob.AssetMergeBatch
			 (RowStatus, Guid, SourceAssetId, TargetAssetId, CreatedByUserId, CheckedByUserId, IsComplete)
		VALUES
			 (
				 1,					-- RowStatus - tinyint
				 @Guid,				-- Guid - uniqueidentifier
				 @SourceAssetId,	-- SourceAssetId - int
				 @TargetAssetId,	-- TargetAssetId - int
				 @CreatedByUserId,	-- CreatedByUserId - int
				 @CheckedByUserId,	-- CheckedByUserId - int
				 0					-- IsComplete - bit
			 );

	END;
	ELSE
	BEGIN
		UPDATE	SJob.AssetMergeBatch
		SET		SourceAssetId = @SourceAssetId,
				TargetAssetId = @TargetAssetId,
				CheckedByUserId = @CheckedByUserId
		WHERE	(Guid = @Guid);
	END;

	IF (@CheckedByUserId > -1)
	BEGIN
		EXEC SJob.MergeAssets @FromAssetGuid = @SourceAssetGuid,	-- uniqueidentifier
								@ToAssetGuid = @TargetAssetGuid;	-- uniqueidentifier

		UPDATE	SJob.AssetMergeBatch
		SET		IsComplete = 1
		WHERE	(Guid = @Guid);	
	END;

END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SJob].[JobReopen]
--
GO





CREATE OR ALTER PROCEDURE [SJob].[JobReopen]
  @Guid                    UNIQUEIDENTIFIER OUT
AS
  BEGIN
    DECLARE @UserID             INT = -1;

    SELECT
            @UserID = ISNULL(CONVERT(INT,
            SESSION_CONTEXT(N'user_id')
            ),
            -1
            );

    IF (NOT EXISTS
			(
				SELECT	1
				FROM	SCore.UserGroups AS ug
				JOIN	SCore.Groups AS g ON (g.ID = ug.GroupID)
				WHERE	(ug.IdentityID = @UserID)
					AND	(g.Code = N'JOBSSU')
			)
		)
	BEGIN 
		;THROW 60000, N'Only members of the Job Superusers group can run this action.', 1
	END
	ELSE
	BEGIN 
		UPDATE	j
		SET		j.JobCompleted = NULL
		FROM	SJob.Jobs AS j
		WHERE	(j.Guid = @Guid)
	END
  END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamDormant]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamDormant]
	(
		@UserId INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				jt.Name							  AS JobTypeName,
				i.Guid							  AS SurveyorGuid,
				client.Name + N' / ' + agent.Name AS ClientAgent,
				i.FullName						  AS SurveyorName,
				prop.FormattedAddressComma,
				js.IsSubjectToNDA,
				j.IsComplete,
				js.JobStatus,
				j.JobDormant,
				orgu.Name AS OrgUnit
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus	 AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SJob.Assets	 AS prop ON (prop.ID = j.UprnID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   JOIN		SCrm.Accounts	 AS agent ON (agent.ID = j.AgentAccountID)
	   JOIN     SCore.OrganisationalUnits as orgu ON (orgu.ID = j.OrganisationalUnitID)
	   CROSS APPLY
				(
					SELECT	ou1.OrgNode
					FROM	SCore.OrganisationalUnits AS ou1
					JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
					WHERE	(i1.ID = @UserId)
				)				 AS CurrentUser
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (j.ID		   > 0)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsComplete = 0)
			AND (j.JobDormant IS NOT NULL)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
		   )
				);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_Dormant]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_Dormant] 
(
    @UserId INT
)
RETURNS TABLE
    --WITH SCHEMABINDING
AS
RETURN 
SELECT  j.ID,
        j.RowStatus,
        j.RowVersion,
        j.Guid,
        j.Number,
        j.JobDescription,
        j.JobTypeID,
        jt.Name AS JobTypeName,
		i.Guid SurveyorGuid,
		client.Name + N' / ' + agent.Name AS  ClientAgent,
		i.FullName AS SurveyorName, 
		prop.FormattedAddressComma,
		js.IsSubjectToNDA,
		j.IsComplete,
		js.JobStatus,
		j.JobDormant,
		org.Name AS OrgUnit
FROM    SJob.Jobs j
JOIN	SJob.JobStatus js ON (js.ID = j.ID)
JOIN    SJob.JobTypes jt ON (j.JobTypeID = jt.ID)
JOIN    SCore.Identities i ON (j.SurveyorID = i.ID)
JOIN	SJob.Assets prop ON (prop.ID = j.UprnID)
JOIN	SCrm.Accounts client ON (client.ID = j.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = j.AgentAccountID)
JOIN    SCore.OrganisationalUnits as org ON (org.ID = j.OrganisationalUnitID)
WHERE   (j.RowStatus  NOT IN (0, 254))
	AND	(j.Id > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
	AND	(j.IsComplete = 0)
	AND	(j.JobDormant IS NOT NULL)
	AND	(j.SurveyorID = @UserId)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

