--
-- Create or alter function [SSop].[tvf_QuoteItemsValidate]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteItemsValidate]
	(
		@CreatedJobGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		[IsInformationOnly] [BIT] NOT NULL DEFAULT((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	-- Prevent changing the Quote Item if the Enquiry is no set as ready for quote review. 
	-- This would be the case if the enquiry had been duplicated. 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteItems AS qi
		 JOIN	SSop.Quotes			 AS q ON (q.ID = qi.QuoteId)
		 JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
		 JOIN	SSop.Enquiries		 AS e ON (e.ID	 = es.EnquiryId)
		 WHERE	(qi.Guid					 = @Guid)
			AND (e.IsReadyForQuoteReview = 0)
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT
				 ep.Guid,
				 N'P',
				 1,
				 0,
				 0,
				 N''
		FROM	SCore.EntityProperties AS ep
		JOIN	SCore.EntityHobts AS eh ON (eh.ID = ep.EntityHoBTID)
		JOIN	SCore.EntityTypes AS et ON (et.ID = eh.EntityTypeID)
		WHERE	(et.Name = N'QuoteItems')

		RETURN;
	END;


    IF (EXISTS 
			(
				SELECT	1
				FROM	SSop.QuoteItems qi 
				JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
				WHERE	(qi.CreatedJobId > 0)
					AND	(qi.Guid = @Guid)
					AND	((q.IsFinal = 1)
					OR	(q.DateSent IS NOT NULL))
			)	
	)
    BEGIN 
        DECLARE @EntityTypeGuid UNIQUEIDENTIFIER = '6474b796-c20d-4947-9406-ae1b6dffef32'

        INSERT @ValidationResult (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, [Message])
        VALUES (@EntityTypeGuid, N'E', 1, 0, 0, N'')
    END

	IF (@CreatedJobGuid = '00000000-0000-0000-0000-000000000000')
			BEGIN

				INSERT @ValidationResult
						(
							TargetGuid,
							TargetType,
							IsReadOnly,
							IsHidden,
							IsInvalid,
							[Message]
						)
				SELECT
							epfvv.Guid,
							N'P',
							1,
							1,
							0,
							N''
				FROM	SCore.EntityPropertiesForValidationV AS epfvv
				WHERE	([epfvv].[Schema] = N'SSop')
					AND	(epfvv.Hobt = N'QuoteItems')
					AND	(Name = (N'CreatedJobId'))
								
			
			END

	RETURN;
END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[EnquiriesDuplicate]
--
GO
CREATE OR ALTER PROCEDURE [SSop].[EnquiriesDuplicate]
	@SourceGuid UNIQUEIDENTIFIER,
	@TargetGuid UNIQUEIDENTIFIER
AS
	BEGIN

		DECLARE @SourceID INT,
				@SourceNumber NVARCHAR(50),
				@ID		  INT,
				@IsInsert BIT;

		SELECT
				@SourceID = ID,
				@SourceNumber = Number
		FROM
				SSop.Enquiries
		WHERE
				(Guid = @SourceGuid);

		IF (@@ROWCOUNT > 1)
			BEGIN
				;
				THROW 60000, N'Invalid source Enquiry', 1;
			END;

		EXEC SCore.UpsertDataObject
			@Guid					= @TargetGuid,
			@SchemeName				= N'SSop',
			@ObjectName				= N'Enquiries',
			@IncludeDefaultSecurity = 1,
			@IsInsert				= @IsInsert


		INSERT	SSop.Enquiries
			 (RowStatus,
			  Guid,
			  OrganisationalUnitID,
			  Date,
			  CreatedByUserId,
			  Number,
			  PropertyId,
			  PropertyNameNumber,
			  PropertyAddressLine1,
			  PropertyAddressLine2,
			  PropertyAddressLine3,
			  PropertyTown,
			  PropertyCountyId,
			  PropertyPostCode,
			  PropertyCountryId,
			  ClientAccountId,
			  ClientAddressId,
			  ClientAccountContactId,
			  ClientName,
			  ClientAddressNameNumber,
			  ClientAddressLine1,
			  ClientAddressLine2,
			  ClientAddressLine3,
			  ClientAddressTown,
			  ClientAddressCountyId,
			  ClientAddressPostCode,
			  ClientAddressCountryId,
			  AgentAccountId,
			  AgentAddressId,
			  AgentAccountContactId,
			  AgentName,
			  AgentAddressNameNumber,
			  AgentAddressLine1,
			  AgentAddressLine2,
			  AgentAddressLine3,
			  AgentTown,
			  AgentCountyId,
			  AgentAddressPostCode,
			  AgentCountryId,
			  DescriptionOfWorks,
			  ValueOfWork,
			  CurrentProjectRibaStageID,
			  RibaStage0Months,
			  RibaStage1Months,
			  RibaStage2Months,
			  RibaStage3Months,
			  RibaStage4Months,
			  RibaStage5Months,
			  RibaStage6Months,
			  RibaStage7Months,
			  PreConstructionStageMonths,
			  ConstructionStageMonths,
			  SendInfoToClient,
			  SendInfoToAgent,
			  KeyDates,
			  ExpectedProcurementRoute,
			  Notes,
			  EnquirySourceId,
			  IsReadyForQuoteReview,
			  QuotingDeadlineDate,
			  DeclinedToQuoteDate,
			  DeclinedToQuoteReason,
			  ExternalReference,
			  ProjectId,
			  IsSubjectToNDA,
			  DeadDate,
			  ChaseDate1,
			  ChaseDate2,
			  IsClientFinanceAccount,
			  FinanceAccountId,
			  FinanceAddressId,
			  FinanceContactId,
			  FinanceAccountName,
			  FinanceAddressNameNumber,
			  FinanceAddressLine1,
			  FinanceAddressLine2,
			  FinanceAddressLine3,
			  FinanceTown,
			  FinanceCountyId,
			  FinancePostCode,
			  EnterNewClientDetails,
			  EnterNewAgentDetails,
			  EnterNewFinanceDetails,
			  EnterNewStructureDetails,
			  SignatoryIdentityId,
			  ProposalLetter,
			  ClientContactDisplayName,
			  ClientContactDetailType,
			  ClientContactDetailTypeName,
			  ClientContactDetailTypeValue,
			  AgentContactDisplayName,
			  AgentContactDetailType,
			  AgentContactDetailTypeName,
			  AgentContactDetailTypeValue,
			  FinanceContactDisplayName,
			  FinanceContactDetailType,
			  FinanceContactDetailTypeName,
			  FinanceContactDetailTypeValue)
		SELECT
				 0,	-- RowStatus - tinyint
				 @TargetGuid,	-- Guid - uniqueidentifier
				 e.OrganisationalUnitID,	-- OrganisationalUnitID - int
				 e.Date,	-- Date - datetime2(7)
				 e.CreatedByUserId,	-- CreatedByUserId - int
				 (0),	-- Number - nvarchar(50)
				 e.PropertyId,	-- PropertyId - int
				 e.PropertyNameNumber,	-- PropertyNameNumber - nvarchar(100)
				 e.PropertyAddressLine1,	-- PropertyAddressLine1 - nvarchar(255)
				 e.PropertyAddressLine2,	-- PropertyAddressLine2 - nvarchar(255)
				 e.PropertyAddressLine3,	-- PropertyAddressLine3 - nvarchar(255)
				 e.PropertyTown,	-- PropertyTown - nvarchar(255)
				 e.PropertyCountyId,	-- PropertyCountyId - int
				 e.PropertyPostCode,	-- PropertyPostCode - nvarchar(30)
				 e.PropertyCountryId,	-- PropertyCountryId - int
				 e.ClientAccountId,	-- ClientAccountId - int
				 e.ClientAddressId,	-- ClientAddressId - int
				 e.ClientAccountContactId,	-- ClientAccountContactId - int
				 e.ClientName,	-- ClientName - nvarchar(250)
				 e.ClientAddressNameNumber,	-- ClientAddressNameNumber - nvarchar(100)
				 e.ClientAddressLine1,	-- ClientAddressLine1 - nvarchar(255)
				 e.ClientAddressLine2,	-- ClientAddressLine2 - nvarchar(255)
				 e.ClientAddressLine3,	-- ClientAddressLine3 - nvarchar(255)
				 e.ClientAddressTown,	-- ClientAddressTown - nvarchar(255)
				 e.ClientAddressCountyId,	-- ClientAddressCountyId - int
				 e.ClientAddressPostCode,	-- ClientAddressPostCode - nvarchar(30)
				 e.ClientAddressCountryId,	-- ClientAddressCountryId - int
				 e.AgentAccountId,	-- AgentAccountId - int
				 e.AgentAddressId,	-- AgentAddressId - int
				 e.AgentAccountContactId,	-- AgentAccountContactId - int
				 e.AgentName,	-- AgentName - nvarchar(250)
				 e.AgentAddressNameNumber,	-- AgentAddressNameNumber - nvarchar(100)
				 e.AgentAddressLine1,	-- AgentAddressLine1 - nvarchar(255)
				 e.AgentAddressLine2,	-- AgentAddressLine2 - nvarchar(255)
				 e.AgentAddressLine3,	-- AgentAddressLine3 - nvarchar(255)
				 e.AgentTown,	-- AgentTown - nvarchar(255)
				 e.AgentCountyId,	-- AgentCountyId - int
				 e.AgentAddressPostCode,	-- AgentAddressPostCode - nvarchar(30)
				 e.AgentCountryId,	-- AgentCountryId - int
				 e.DescriptionOfWorks,	-- DescriptionOfWorks - nvarchar(4000)
				 e.ValueOfWork,	-- ValueOfWork - decimal(19, 2)
				 e.CurrentProjectRibaStageID,	-- CurrentProjectRibaStageID - int
				 e.RibaStage0Months,	-- RibaStage0Months - int
				 e.RibaStage1Months,	-- RibaStage1Months - int
				 e.RibaStage2Months,	-- RibaStage2Months - int
				 e.RibaStage3Months,	-- RibaStage3Months - int
				 e.RibaStage4Months,	-- RibaStage4Months - int
				 e.RibaStage5Months,	-- RibaStage5Months - int
				 e.RibaStage6Months,	-- RibaStage6Months - int
				 e.RibaStage7Months,	-- RibaStage7Months - int
				 e.PreConstructionStageMonths,	-- PreConstructionStageMonths - int
				 e.ConstructionStageMonths,	-- ConstructionStageMonths - int
				 e.SendInfoToClient,	-- SendInfoToClient - bit
				 e.SendInfoToAgent,	-- SendInfoToAgent - bit
				 e.KeyDates,	-- KeyDates - nvarchar(2000)
				 e.ExpectedProcurementRoute,	-- ExpectedProcurementRoute - nvarchar(200)
				 e.Notes,	-- Notes - nvarchar(max)
				 e.EnquirySourceId,	-- EnquirySourceId - int
				 (0),	-- IsReadyForQuoteReview - bit
				 NULL,		-- QuotingDeadlineDate - date
				 NULL,		-- DeclinedToQuoteDate - date
				 N'',	-- DeclinedToQuoteReason - nvarchar(4000)
				 e.ExternalReference,	-- ExternalReference - nvarchar(50)
				 e.ProjectId,	-- ProjectId - int
				 e.IsSubjectToNDA,	-- IsSubjectToNDA - bit
				 NULL,		-- DeadDate - date
				 NULL,		-- ChaseDate1 - date
				 NULL,		-- ChaseDate2 - date
				 e.IsClientFinanceAccount,	-- IsClientFinanceAccount - bit
				 e.FinanceAccountId,	-- FinanceAccountId - int
				 e.FinanceAddressId,	-- FinanceAddressId - int
				 e.FinanceContactId,	-- FinanceContactId - int
				 e.FinanceAccountName,	-- FinanceAccountName - nvarchar(250)
				 e.FinanceAddressNameNumber,	-- FinanceAddressNameNumber - nvarchar(100)
				 e.FinanceAddressLine1,	-- FinanceAddressLine1 - nvarchar(255)
				 e.FinanceAddressLine2,	-- FinanceAddressLine2 - nvarchar(255)
				 e.FinanceAddressLine3,	-- FinanceAddressLine3 - nvarchar(255)
				 e.FinanceTown,	-- FinanceTown - nvarchar(255)
				 e.FinanceContactId,	-- FinanceCountyId - int
				 e.FinancePostCode,	-- FinancePostCode - nvarchar(30)
				 e.EnterNewClientDetails,	-- EnterNewClientDetails - bit
				 e.EnterNewAgentDetails,	-- EnterNewAgentDetails - bit
				 e.EnterNewFinanceDetails,	-- EnterNewFinanceDetails - bit
				 e.EnterNewStructureDetails,	-- EnterNewStructureDetails - bit
				 e.SignatoryIdentityId,	-- SignatoryIdentityId - int
				 e.ProposalLetter,	-- ProposalLetter - nvarchar(max)
				 e.ClientContactDisplayName, --ClientContactDisplayName nvarchar(250)
				 e.ClientContactDetailType,  --ClientContactDetailType smallint
				 e.ClientContactDetailTypeName, --ClientContactDetailTypeName nvarchar(100)
				 e.ClientContactDetailTypeValue, --ClientContactDetailTypeValue nvarchar(250)
				 e.AgentContactDisplayName, --AgentContactDisplayName nvarchar(250)
				 e.AgentContactDetailType,  --AgentContactDetailType smallint
				 e.AgentContactDetailTypeName, --AgentContactDetailTypeName nvarchar(100)
				 e.AgentContactDetailTypeValue, --AgentContactDetailTypeValue nvarchar(250)
				 e.FinanceContactDisplayName, --FinanceContactDisplayName nvarchar(250)
				 e.FinanceContactDetailType, --FinanceContactDetailType smallint
				 e.FinanceContactDetailTypeName, --FinanceContactDetailTypeName nvarchar(100)
				 e.FinanceContactDetailTypeValue --FinanceContactDetailTypeValue nvarchar(250)

		FROM	SSop.Enquiries AS e
		WHERE	(e.Guid = @SourceGuid)

		SELECT
				@ID = SCOPE_IDENTITY();

		-- Build the collection of Enquiry Services to duplicate. 
		DECLARE	@EnquiryServices SCore.TwoGuidUniqueList

		INSERT	@EnquiryServices
			 (GuidValue, GuidValueTwo)
		SELECT	es.Guid,
				NEWID()
		FROM	SSop.EnquiryServices AS es
		JOIN	SSop.Enquiries AS e ON (e.ID = es.EnquiryId)
		WHERE	(e.Guid = @SourceGuid)

		-- Create the data objects. 
		DECLARE @NewGuidList SCore.GuidUniqueList

		INSERT @NewGuidList
				(
					GuidValue
				)
			SELECT
					GuidValueTwo
			FROM
					@EnquiryServices

		EXEC SCore.DataObjectBulkUpsert
			@GuidList   = @NewGuidList,				-- GuidUniqueList
			@SchemeName = N'SSop',				-- nvarchar(255)
			@ObjectName = N'EnquiryServices',				-- nvarchar(255)
			@IsInsert   = @IsInsert OUTPUT	-- bit

		DELETE FROM
		@NewGuidList

		INSERT	SSop.EnquiryServices
			 (RowStatus, Guid, EnquiryId, JobTypeId, StartRibaStageId, EndRibaStageId, QuoteId)
		SELECT	1, 
				es.GuidValueTwo, 
				@ID, 
				es2.JobTypeId, 
				es2.StartRibaStageId,
				es2.EndRibaStageId,
				-1
		FROM	@EnquiryServices AS es
		JOIN	SSop.EnquiryServices AS es2 ON (es.GuidValue = es2.Guid)
				
		DECLARE	@ServiceQuoteList AS SCore.ThreeGuidUniqueList,	
				@CurrentQuote UNIQUEIDENTIFIER,
				@NewQuoteGuid UNIQUEIDENTIFIER,
				@MaxQuote UNIQUEIDENTIFIER

		INSERT	@ServiceQuoteList
			 (GuidValue, GuidValueTwo, GuidValueThree)
		SELECT	q.Guid,
				NEWID(),
				es2.GuidValueTwo
		FROM	SSop.Quotes AS q
		JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
		JOIN	@EnquiryServices AS es2 ON (es.Guid = es2.GuidValue)


		INSERT @NewGuidList
				(
					GuidValue
				)
			SELECT
					GuidValueTwo
			FROM
					@EnquiryServices

		EXEC SCore.DataObjectBulkUpsert
			@GuidList   = @NewGuidList,				-- GuidUniqueList
			@SchemeName = N'SSop',				-- nvarchar(255)
			@ObjectName = N'EnquiryServices',				-- nvarchar(255)
			@IsInsert   = @IsInsert OUTPUT	-- bit	

		DELETE FROM
		@NewGuidList	
		
		SELECT	@MaxQuote = MAX(GuidValue),
				@CurrentQuote = '00000000-0000-0000-0000-000000000000'
		FROM	@ServiceQuoteList AS tgul

		WHILE	@CurrentQuote < @MaxQuote
		BEGIN 
			SELECT	@CurrentQuote = GuidValue,
					@NewQuoteGuid = GuidValueTwo
			FROM	@ServiceQuoteList
			WHERE	(GuidValue > @CurrentQuote)
			ORDER BY	GuidValue

			EXEC SSop.QuotesDuplicate @SourceGuid = @CurrentQuote,	-- uniqueidentifier
									  @TargetGuid = @NewQuoteGuid	-- uniqueidentifier

			UPDATE	q
			SET		EnquiryServiceId = es.ID
			FROM	SSop.Quotes AS q
			JOIN	@ServiceQuoteList AS ql ON (q.Guid = ql.GuidValueTwo)
			JOIN	SSop.EnquiryServices AS es ON (es.Guid = ql.GuidValueThree)
			
		END

		DECLARE	@UserID INT = SCore.GetCurrentUserId(),
				@NewValue NVARCHAR(500) = N'Duplicated from ' + @SourceNumber

		INSERT	SCore.RecordHistory
			 (Guid,
			  RowStatus,
			  SchemaName,
			  TableName,
			  ColumnName,
			  RowID,
			  RowGuid,
			  Datetime,
			  UserID,
			  SQLUser,
			  PreviousValue,
			  NewValue,
			  EntityPropertyID)
		VALUES
			 (
				 NEWID(),	-- Guid - uniqueidentifier
				 1,	-- RowStatus - tinyint
				 N'SSop',	-- SchemaName - nvarchar(250)
				 N'Enquiries',	-- TableName - nvarchar(250)
				 N'',	-- ColumnName - nvarchar(250)
				 @ID,	-- RowID - bigint
				 @TargetGuid,	-- RowGuid - uniqueidentifier
				 GETUTCDATE(),	-- Datetime - datetime
				 @UserID,	-- UserID - int
				 N'',	-- SQLUser - nvarchar(250)
				 N'',	-- PreviousValue - nvarchar(max)
				 @NewValue,	-- NewValue - nvarchar(max)
				 -1	-- EntityPropertyID - int
			 )
	

		-- Allocate a new Enquiry number. 

		DECLARE @EnquiryNumber NVARCHAR(30);

		SELECT
				@EnquiryNumber = NEXT VALUE FOR SSop.EnquiryNumber;

		UPDATE  SSop.Enquiries
		SET		Number = @EnquiryNumber,
				RowStatus = 1
		WHERE
			(ID = @ID);
	END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuoteItemsUpsert]
--
GO
CREATE OR ALTER PROCEDURE [SSop].[QuoteItemsUpsert]
  (
    @QuoteGuid    UNIQUEIDENTIFIER,
    @ProductGuid         UNIQUEIDENTIFIER,
    @Details             NVARCHAR(2000),
    @Net                 DECIMAL(19, 2),
    @VatRate             DECIMAL(9, 2),
    @DoNotConsolidateJob BIT,
    @SortOrder           INT,
    @Quantity            DECIMAL(9, 2),
	@ProvidedAtStageGuid UNIQUEIDENTIFIER,
    @Guid                UNIQUEIDENTIFIER,
	@NumberOfSiteVisits		 INT,
	@NumberOfMeetings    INT
  )
AS
  BEGIN
    DECLARE @QuoteId INT,
            @ProductId      INT,
			@ProvidedAtStageId INT,
            @IsInsert       BIT;

    SELECT
            @QuoteId = ID
    FROM
            SSop.Quotes
    WHERE
            ([Guid] = @QuoteGuid)

    SELECT
            @ProvidedAtStageId = ID
    FROM
            SJob.RibaStages AS rs
    WHERE
            ([Guid] = @ProvidedAtStageGuid)

	SELECT
            @ProductId = ID
    FROM
            SProd.Products
    WHERE
            ([Guid] = @ProductGuid)

    EXEC SCore.UpsertDataObject
      @Guid       = @Guid,					-- uniqueidentifier
      @SchemeName = N'SSop',				-- nvarchar(255)
      @ObjectName = N'QuoteItems',				-- nvarchar(255)
      @IsInsert   = @IsInsert OUTPUT	-- bit

    IF (@IsInsert = 1)
      BEGIN
        INSERT SSop.QuoteItems
              (
                RowStatus,
                Guid,
                QuoteId,
                ProductId,
                Details,
                Net,
                VatRate,
                DoNotConsolidateJob,
                SortOrder,
                Quantity,
				ProvideAtStageID,
				NumberOfMeetings,
				NumberOfSiteVisits
              )
        VALUES
                (
                  1,	-- RowStatus - tinyint
                  @Guid,	-- Guid - uniqueidentifier
                  @QuoteId,	-- QuoteSectionId - int
                  @ProductId,	-- ProductId - int
                  @Details,	-- Details - nvarchar(2000)
                  @Net,	-- Net - decimal(9, 2)
                  @VatRate,	-- VatRate - decimal(9, 2)
                  @DoNotConsolidateJob,	-- DoNotConsolidateJob - bit
                  @SortOrder,	-- SortOrder - int
                  @Quantity,
				  @ProvidedAtStageId,
				  @NumberOfMeetings,
				  @NumberOfSiteVisits
                )
      END
    ELSE
      BEGIN
        UPDATE  SSop.QuoteItems
        SET     QuoteId = @QuoteId,
                ProductId = @ProductId,
                Details = @Details,
                Net = @Net,
                VatRate = @VatRate,
                DoNotConsolidateJob = @DoNotConsolidateJob,
                SortOrder = @SortOrder,
                Quantity = @Quantity,
				ProvideAtStageID = @ProvidedAtStageId,
				NumberOfMeetings = @NumberOfMeetings,
				NumberOfSiteVisits = @NumberOfSiteVisits
        WHERE
          ([Guid] = @Guid)
      END
  END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiriesForQuoteReview]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesForQuoteReview]
(
	@UserId INT
)
RETURNS TABLE
            --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		e.Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN acc.Name <> N'' THEN acc.Name ELSE e.ClientName END AS Account,
		-- New fields
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SCrm.Accounts acc ON (acc.ID = e.ClientAccountID)
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.IsReadyForQuoteReview = 1)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(NOT EXISTS
							(
								SELECT	1
								FROM	SSop.Quotes AS q
								WHERE	(q.EnquiryServiceID = es.ID)
									AND	(q.RowStatus NOT IN (0, 254))
							)
						)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuotesReadyToSend]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesReadyToSend]
(
	@UserId INT
)
RETURNS TABLE
	   --WITH SCHEMABINDING
AS RETURN	
SELECT  q.ID,
        q.RowStatus,
        q.RowVersion,
        q.Guid,
		q.FullNumber AS Number,
		CASE WHEN q.DescriptionOfWorks <> N'' THEN LEFT(q.DescriptionOfWorks, 200) ELSE LEFT(q.Overview, 200) END AS Details,
		acc.Name + N' / ' + aacc.Name AS Account,
		uprn.FormattedAddressComma,
		i.FullName AS QuotingConsultant,
		qcf.QuoteStatus AS QuoteStatus
FROM    SSop.Quotes q
JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
JOIN	SSop.Enquiries AS e ON (e.ID = es.EnquiryId)
JOIN	SCrm.Accounts acc ON (acc.ID = e.ClientAccountID)
JOIN	SCrm.Accounts aacc ON (aacc.ID = e.AgentAccountID)
JOIN	SCore.Identities i ON (i.ID = q.QuotingConsultantId)
JOIN	SJob.Assets uprn ON (uprn.ID = q.UprnId)
JOIN	SSop.Quote_CalculatedFields qcf ON (qcf.ID = q.ID)
WHERE   (q.RowStatus NOT IN (0, 254))
	AND	(q.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(q.Guid, @UserId) oscr
			)
		)
	AND	(q.IsFinal = 1)
	AND	(q.DateSent IS NULL)
	AND	(q.DateAccepted IS NULL)
	AND	(q.DateRejected IS NULL)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuotesValidate]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@DateSent DATE,
		@DeadDate DATE,
		@DateRejected DATE,
		@IsFinal BIT,
		@RevisionNumber INT,
		@OrganisationalUnitGuid UNIQUEIDENTIFIER,
		@DateDeclinedToQuote DATE,
		@DeclinedToQuoteReason NVARCHAR(MAX)
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityTypeGuid UNIQUEIDENTIFIER = '1c4794c1-f956-4c32-b886-5500ac778a56';

	-- Prevent changing the Quote if the Enquiry is no set as ready for quote review. 
	-- This would be the case if the enquiry had been duplicated. 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes			 AS q
		 JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
		 JOIN	SSop.Enquiries		 AS e ON (e.ID	 = es.EnquiryId)
		 WHERE	(q.Guid					 = @Guid)
			AND (e.IsReadyForQuoteReview = 0)
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT
				 ep.Guid,
				 N'P',
				 1,
				 0,
				 0,
				 N''
		FROM	SCore.EntityProperties AS ep
		JOIN	SCore.EntityHobts AS eh ON (eh.ID = ep.EntityHoBTID)
		JOIN	SCore.EntityTypes AS et ON (et.ID = eh.EntityTypeID)
		WHERE	(et.Name = N'Quotes')

		RETURN;
	END;


	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteItems AS qi
		 JOIN	SSop.Quotes		AS q ON (q.ID = qi.QuoteId)
		 WHERE	(q.Guid			 = @Guid)
			AND (qi.RowStatus NOT IN (0, 254))
			AND (qi.CreatedJobId > 0)
	 )
	   )
	OR	(@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityTypeGuid,
				 N'E',
				 1,
				 0,
				 0,
				 N''
			 );

		RETURN;
	END;

	-- Hide fields from CDM based quotes 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SCore.OrganisationalUnits AS ou
		 WHERE	(ou.Guid = @OrganisationalUnitGuid)
			AND (ou.Name LIKE N'CDM%')
	 )
	   )
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'FeeCap');
	END;

	/*IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteSections AS qs
		 JOIN	SSop.Quotes		   AS q ON (q.ID = qs.QuoteId)
		 WHERE	(q.Guid			= @Guid)
			AND (qs.RibaStageId < 0)
			AND (qs.RowStatus NOT IN (0, 254))
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'All sections must have a Stage set.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'Number');
	END;*/

	IF (@RevisionNumber < 1)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= (N'RevisionNumber'));


	END;

	--[CBLD-592] Check if the DeclinedToQuoteDate is set & there is no reason why it's been declined.
	IF (
		   @DateDeclinedToQuote IS NOT NULL
	   AND	@DeclinedToQuoteReason = N''
	   )
	BEGIN
		DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER;
		SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																	  N'Quotes',
																	  N'DeclinedToQuoteReason'
																  );

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 0,
				 0,
				 1,
				 N'You must enter the reason why we declined to quote.'
			 );
	END;

	----[CBLD-592] Check if the DeclinedToQuoteDate is set - if it is, set IsReadOnly for the whole form.
	IF (
		   @DateDeclinedToQuote IS NOT NULL
	   AND	@DeclinedToQuoteReason <> N''
	   AND	NOT EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	q.Guid					= @Guid
			AND q.DeclinedToQuoteReason = N''
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes');

		RETURN;
	END;

	/* Don't allow the user to progress the status further than Send until the quote has been marked as Sent. */
	IF (@DateSent IS NULL)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name IN (N'DateAccepted', N'DateRejected', N'RejectionReason', N'ChaseDate1', N'ChaseDate2'));

	END;

	/* Once the quote has been sent you can't unset it as "Is Final" */
	IF (@DateSent IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'IsFinal');
	END;

	/* Don't allow the quote to be sent until it has been set as "Is Final" */
	IF (@IsFinal = 0)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'DateSent');
	END;

	/* Hide Rejection Reason if the Quote hasn't been rejected. */
	IF (@DateRejected IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'RejectionReason');
	END;



	IF (@IsFinal = 1)
   AND	(NOT EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid						= @Guid)
			AND (q.LegacyId IS NOT NULL)
			AND
				(
					(q.OrganisationalUnitID < 0)
				 OR (q.QuotingUserId		< 0)
				 OR (q.QuotingConsultantId	< 0)
				)
	 )
		)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name NOT IN (N'ChaseDate2', N'ChaseDate1', N'RejectionReason', N'DateRejected', N'DateAccepted',
									N'IsFinal', N'DateSent'
								   )
				);

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quote_ExtendedInfo')
		
				


		IF (ISNULL (
				 (
					 SELECT SUM (qit.LineNet)
					 FROM	SSop.QuoteItemTotals AS qit
					 JOIN	SSop.QuoteItems		 AS qi ON (qi.ID = qit.ID)
					 JOIN	SSop.Quotes			 AS q ON (q.ID	 = qi.QuoteId)
					 WHERE	(q.Guid = @Guid)
						AND (qi.RowStatus NOT IN (0, 254))
				 ),
				 0
				   ) <= 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'A final quote must have a net value greater than 0.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Quotes')
				AND (epfvv.Name		= N'IsFinal');
		END;

	END;



	RETURN;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiriesValidate]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@RowStatus TINYINT,
		@PropertyGuid UNIQUEIDENTIFIER,
		@ClientAccountGuid UNIQUEIDENTIFIER,
		@ClientAddressGuid UNIQUEIDENTIFIER,
		@AgentAccountGuid UNIQUEIDENTIFIER,
		@AgentAddressGuid UNIQUEIDENTIFIER,
		@FinanceAccountGuid UNIQUEIDENTIFIER,
		@FinanceAddressGuid UNIQUEIDENTIFIER,
		@IsReadyForQuoteReview BIT,
		@DescriptionOfWorks NVARCHAR(MAX),
		@ValueOfWork DECIMAL(9, 2),
		@CurrentProjectRibaStageGuid UNIQUEIDENTIFIER,
		@PropertyNumber NVARCHAR(100),
		@PropertyPostCode NVARCHAR(30),
		@ClientAddressNumber NVARCHAR(100),
		@ClientAddressPostCode NVARCHAR(30),
		@AgentAddressNumber NVARCHAR(100),
		@AgentAddressPostCode NVARCHAR(30),
		@AgentName NVARCHAR(250),
		@ClientName NVARCHAR(250),
		@DeclinedToQuoteDate DATE,
		@DeclinedToQuoteReason NVARCHAR(4000),
		@KeyDates NVARCHAR(2000),
		@DeadDate DATE,
		@EnterNewClientDetails BIT,
		@EnterNewAgentDetails BIT,
		@EnterNewFinanceDetails BIT,
		@EnterNewStructureDetails BIT,
		@IsClientFinanceAccount BIT,
		@ProjectGuid UNIQUEIDENTIFIER,
		@ClientContactDisplayName NVARCHAR(250),
		@AgentContactDisplayName NVARCHAR(250),
		@FinanceContactDisplayName NVARCHAR(250),
		@ClientContactDetailType UNIQUEIDENTIFIER,
		@ClientContactDetailTypeName NVARCHAR(100),
		@ClientContactDetailTypeValue NVARCHAR(250),
		@AgentContactDetailType UNIQUEIDENTIFIER,
		@AgentContactDetailTypeName NVARCHAR(100),
		@AgentContactDetailTypeValue NVARCHAR(250),
		@FinanceContactDetailType UNIQUEIDENTIFIER,
		@FinanceContactDetailTypeName NVARCHAR(100),
		@FinanceContactDetailTypeValue NVARCHAR(250)
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER;

	/*
		Hide the Declinded to quote reason if there's no declined to quote date. 
	*/
	IF (@DeclinedToQuoteDate IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'DeclinedToQuoteReason';
	END;

	/*
		Hide the old key dates field if it wasn't populated. 
	*/
	IF (@KeyDates = N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'KeyDates';
	END;

	/*
		Ensure a reason has been given if we've declined to quote. 
	*/
	IF (@DeclinedToQuoteDate IS NOT NULL)
   AND	(@DeclinedToQuoteReason = N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'You must enter the reason why we declined to quote.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'DeclinedToQuoteReason';
	END;

	/*
		If there's both a declined to quote date and reason, lock these fields down. 
	*/
	IF (@DeclinedToQuoteDate IS NOT NULL)
   AND	(@DeclinedToQuoteReason <> N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name NOT IN (N'DeclinedToQuoteDate', N'DeclinedToQuoteReason');
	END;

	/* 
		If there's a dead date. Lock everything down except that field. 
	*/
	IF (@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   <> N'DeadDate';
	END;

	/* Hide show manual property entry.  */
	IF (
		   @PropertyGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewStructureDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'PropertyNameNumber', N'PropertyAddressLine1', N'PropertyAddressLine2',
							   N'PropertyAddressLine3', N'PropertyTown', N'PropertyCountyId', N'PropertyPostCode',
							   N'PropertyCountryId'
							  
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'PropertyID');
	END;

	/*
		Ensure that if the user is manually entering the client/agent/finance details - along with contact details -
		that any field pertaining to the contact details are made compulsory once the "...ContactDisplayName" has been filled.
	*/

	--Client
	IF (
			@EnterNewClientDetails = 1 AND 
			@ClientContactDisplayName <> N'' AND 
			(
				@ClientContactDetailType = '00000000-0000-0000-0000-000000000000' OR
				@ClientContactDetailTypeName = N'' OR
				@ClientContactDetailTypeValue = N''
			)
		)
	BEGIN
	INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'Please enter contact details for client.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'ClientContactDetailType', N'ClientContactDetailTypeName',N'ClientContactDetailTypeValue', N'');

	END;


	--Agent
	IF (
			@EnterNewAgentDetails = 1 AND 
			@AgentContactDisplayName <> N'' AND
			(
				@AgentContactDetailType = '00000000-0000-0000-0000-000000000000' OR
				@AgentContactDetailTypeName = N'' OR
				@AgentContactDetailTypeValue = N''
			)
		)
	BEGIN
	INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'Please enter contact details for agent account.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'AgentContactDetailType', N'AgentContactDetailTypeName',N'AgentContactDetailTypeValue', N'');

	END;

	--Finance
	IF (
			@EnterNewFinanceDetails = 1 AND 
			@FinanceContactDisplayName <> N'' AND
			(
				@FinanceContactDetailType = '00000000-0000-0000-0000-000000000000' OR
				@FinanceContactDetailTypeName = N'' OR
				@FinanceContactDetailTypeValue = N''
			)
		)
	BEGIN
	INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'Please enter contact details for finance account.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceContactDetailType', N'FinanceContactDetailTypeName',N'FinanceContactDetailTypeValue', N'');

	END;

	/* Hide / Show Manual Client Entry */
	IF (
		   @ClientAccountGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewClientDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'ClientName';
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAccountID');
	END;

	/* Hide show manual client Address Entry */
	IF (
		   @ClientAddressGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewClientDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAddressNameNumber', N'ClientAddressLine1', N'ClientAddressLine2',
							   N'ClientAddressLine3', N'ClientAddressTown', N'ClientAddressCountyId',
							   N'ClientAddressPostCode', N'ClientAddressCountryId',
							    N'ClientContactDisplayName',N'ClientContactDetailType',N'ClientContactDetailTypeName',N'ClientContactDetailTypeValue' --CBLD-653
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAddressID', N'ClientAccountContactID');  
	END;

	/* Hide Show Manual Agent Entry */
	IF (
		   @AgentAccountGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewAgentDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'AgentName';
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAccountID');
	END;

	/* Hide show manual agent address entry */
	IF (
		   @AgentAddressGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewAgentDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAddressNameNumber', N'AgentAddressLine1', N'AgentAddressLine2',
							   N'AgentAddressLine3', N'AgentTown', N'AgentCountyId', N'AgentAddressPostCode',
							   N'AgentCountryId', N'AgentContactDisplayName', N'AgentContactDetailType', N'AgentContactDetailTypeName', N'AgentContactDetailTypeValue'
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAddressID', N'AgentAccountContactID');
	END;

	/* Hide show manual finance account entry */
	IF (@IsClientFinanceAccount = 1)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epg.Guid,
				N'G',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertyGroups AS epg
		JOIN	SCore.EntityTypes		   AS et ON (et.ID = epg.EntityTypeID)
		WHERE	(epg.Name = N'Finance Account Details')
			AND (et.Name  = N'Enquiries');
	END;
	ELSE
	BEGIN
		IF (
			   @FinanceAccountGuid <> '00000000-0000-0000-0000-000000000000'
			OR	@EnterNewFinanceDetails = 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name	   = N'FinanceAccountName';
		END;
		ELSE
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAccountID');
		END;

		IF (
			   @FinanceAddressGuid <> '00000000-0000-0000-0000-000000000000'
			OR	@EnterNewFinanceDetails = 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAddressNameNumber', N'FinanceAddressLine1', N'FinanceAddressLine2',
								   N'FinanceAddressLine3', N'FinanceTown', N'FinanceCountyId', N'FinancePostCode',
								   N'FinanceContactDisplayName', N'FinanceContactDetailType', N'FinanceContactDetailTypeName', N'FinanceContactDetailTypeValue'
								  );
		END;
		ELSE
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAddressID', N'FinanceContactID');
		END;
	END;

	

	IF (@IsReadyForQuoteReview = 1)
		BEGIN
			IF (@DescriptionOfWorks = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'DescriptionOfWorks'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a description of the works.'
					 );
			END;

			IF (@ValueOfWork = 0)
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ValueOfWork'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a value of work.'
					 );
			END;

			IF (@CurrentProjectRibaStageGuid = '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'CurrentProjectRibaStageId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a current RIBA stage.'
					 );
			END;


			IF (@PropertyGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@PropertyNumber = N'')
		   AND	(@PropertyPostCode = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'PropertyId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until property details have been entered.'
					 );
			END;

			/*
				Don't allow the enquiry to be submitted for quoting until their is a client or agent. 
			*/
			IF (@ClientAccountGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@ClientName = N'')
		   AND	(@AgentAccountGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@AgentName = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ClientAccountId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent account has been entered.'
					 );

				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'AgentAccountId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent account has been entered.'
					 );
			END;

			/*
				Don't allow the enquiry to be submitted for quoting until their is a client or agent. 
			*/
			IF (@ClientAddressGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@ClientAddressNumber = N'')
		   AND	(@ClientAddressPostCode = N'')
		   AND	(@AgentAddressGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@AgentAddressNumber = N'')
		   AND	(@AgentAddressPostCode = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ClientAddressId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent address details have been entered.'
					 );

				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'AgentAddressId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent address details have been entered.'
					 );
			END;
		END;


	/*
		Check if there are quotes in existence. 
	*/
	DECLARE	@IsReadyForQuoteReviewGuid UNIQUEIDENTIFIER = SCore.GetEntityPropertyGuid(N'SSop', N'Enquiries', N'IsReadyForQuoteReview')
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.EnquiryServices AS es
		 JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
		 WHERE	(e.Guid = @Guid)
			AND (es.RowStatus NOT IN (0, 254))
			AND (EXISTS
			 (
				 SELECT 1
				 FROM	SSop.Quotes AS q
				 WHERE	(q.EnquiryServiceID = es.ID)
					AND (q.RowStatus NOT IN (0, 254))
			 )
				)
			AND (EXISTS
						(
							SELECT	1
							FROM	SCore.RecordHistory AS rh
							JOIN	SCore.EntityProperties ep ON (ep.ID = rh.EntityPropertyID)
							WHERE	(ep.Guid = @IsReadyForQuoteReviewGuid)
								AND	(rh.RowGuid = @Guid)
						)
					)
	 )
	   )
	BEGIN
		/*
			Prevent changes to 
				- Ready for Quote, ead Date and Declined to Quote date, 
				- Enquiry and Status Groups
				- Entering adhoc account or structure details. 
			after quotes have been created. 
		*/
		

		IF (EXISTS
		 (
			 SELECT 1
			 FROM	SSop.EnquiryServices AS es
			 JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
			 WHERE	(e.Guid = @Guid)
				AND (es.RowStatus NOT IN (0, 254))
		 )
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epgfvv.Guid,		-- TargetGuid - uniqueidentifier
					epgfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					0,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesGroupsForValidationV AS epgfvv
			WHERE	(epgfvv.EntityType = N'Enquiries')
				AND (epgfvv.Name NOT IN (N'Enquiry', N'Status'));

			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epfvv.Guid,			-- TargetGuid - uniqueidentifier
					epfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					1,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Enquiries')
				AND (epfvv.Name IN (N'EnterNewClientDetails', N'EnterNewStructureDetails', N'EnterNewAgentDetails',
									N'EnterNewFinanceDetails'
								   )
					);
		END;

		/* If any of the quotes have reached ceertain states, don't allow the enquiry to be changed. */
		IF (EXISTS
		 (
			 SELECT 1
			 FROM	SSop.EnquiryServices			 AS es
			 JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id	 = es.ID)
			 JOIN	SSop.Enquiries					 AS e ON (e.ID			 = es.EnquiryId)
			 JOIN	SSop.Quote_CalculatedFields		 AS qcf ON (esei.QuoteID = qcf.ID)
			 WHERE	(qcf.QuoteStatus IN (N'Sent', N'Accepted', N'Rejected', N'Complete'))
				AND (e.Guid = @Guid)
				AND	(es.RowStatus NOT IN (0, 254))
		 )
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epgfvv.Guid,		-- TargetGuid - uniqueidentifier
					epgfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					0,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesGroupsForValidationV AS epgfvv
			WHERE	(epgfvv.EntityType = N'Enquiries')
			AND (epgfvv.Name NOT IN (N'Status')) --Do not disable the "Status" group just yet.
		END;

		--Disable everything but the two chase date fields in the "Status" group
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				epfvv.TargetType,
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'IsReadyForQuoteReview', N'DeclinedToQuoteDate', N'DeadDate')
	END;



	RETURN;
END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[EnquiriesRevise]
--
GO
CREATE OR ALTER PROCEDURE [SSop].[EnquiriesRevise] @SourceGuid UNIQUEIDENTIFIER,
									 @TargetGuid UNIQUEIDENTIFIER
AS
BEGIN

	DECLARE @SourceID INT,
			@ID		  INT,
			@IsInsert BIT;

	SELECT	@SourceID = ID
	FROM	SSop.Enquiries
	WHERE	(Guid = @SourceGuid);

	IF (@@ROWCOUNT > 1)
	BEGIN
		;
		THROW 60000, N'Invalid source Enquiry', 1;
	END;

	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Enquiries AS e
		 WHERE	(e.Guid = @SourceGuid)
			AND (EXISTS
					(
						SELECT	1
						FROM	SSop.EnquiryServices AS es
						JOIN	SSop.EnquiryService_ExtendedInfo esei ON (esei.Id = es.ID)
						WHERE	(es.EnquiryId = e.ID)
							AND	(esei.DateAccepted IS NOT NULL)
					)
				)
	 )
	   )
	BEGIN
		; THROW 60000, N'You cannot revise an accepted Enquiry', 1;
	END;

	EXEC SCore.UpsertDataObject @Guid = @TargetGuid,
								@SchemeName = N'SSop',
								@ObjectName = N'Enquiries',
								@IncludeDefaultSecurity = 1,
								@IsInsert = @IsInsert;

	INSERT	SSop.Enquiries
		 (RowStatus,
		  Guid,
		  OrganisationalUnitID,
		  Date,
		  CreatedByUserId,
		  Number,
		  PropertyId,
		  PropertyNameNumber,
		  PropertyAddressLine1,
		  PropertyAddressLine2,
		  PropertyAddressLine3,
		  PropertyTown,
		  PropertyCountyId,
		  PropertyPostCode,
		  PropertyCountryId,
		  ClientAccountId,
		  ClientAddressId,
		  ClientAccountContactId,
		  ClientName,
		  ClientAddressNameNumber,
		  ClientAddressLine1,
		  ClientAddressLine2,
		  ClientAddressLine3,
		  ClientAddressTown,
		  ClientAddressCountyId,
		  ClientAddressPostCode,
		  ClientAddressCountryId,
		  AgentAccountId,
		  AgentAddressId,
		  AgentAccountContactId,
		  AgentName,
		  AgentAddressNameNumber,
		  AgentAddressLine1,
		  AgentAddressLine2,
		  AgentAddressLine3,
		  AgentTown,
		  AgentCountyId,
		  AgentAddressPostCode,
		  AgentCountryId,
		  DescriptionOfWorks,
		  ValueOfWork,
		  CurrentProjectRibaStageID,
		  RibaStage0Months,
		  RibaStage1Months,
		  RibaStage2Months,
		  RibaStage3Months,
		  RibaStage4Months,
		  RibaStage5Months,
		  RibaStage6Months,
		  RibaStage7Months,
		  PreConstructionStageMonths,
		  ConstructionStageMonths,
		  SendInfoToClient,
		  SendInfoToAgent,
		  KeyDates,
		  ExpectedProcurementRoute,
		  Notes,
		  EnquirySourceId,
		  IsReadyForQuoteReview,
		  QuotingDeadlineDate,
		  DeclinedToQuoteDate,
		  DeclinedToQuoteReason,
		  ExternalReference,
		  ProjectId,
		  IsSubjectToNDA,
		  DeadDate,
		  ChaseDate1,
		  ChaseDate2,
		  IsClientFinanceAccount,
		  FinanceAccountId,
		  FinanceAddressId,
		  FinanceContactId,
		  FinanceAccountName,
		  FinanceAddressNameNumber,
		  FinanceAddressLine1,
		  FinanceAddressLine2,
		  FinanceAddressLine3,
		  FinanceTown,
		  FinanceCountyId,
		  FinancePostCode,
		  EnterNewClientDetails,
		  EnterNewAgentDetails,
		  EnterNewFinanceDetails,
		  EnterNewStructureDetails,
		  SignatoryIdentityId,
		  ProposalLetter,
		  Revision,
		  OriginalEnquiryId,
		  ClientContactDisplayName,
		  ClientContactDetailType,
		  ClientContactDetailTypeName,
		  ClientContactDetailTypeValue,
		  AgentContactDisplayName,
		  AgentContactDetailType,
		  AgentContactDetailTypeName,
		  AgentContactDetailTypeValue,
		  FinanceContactDisplayName,
		  FinanceContactDetailType,
		  FinanceContactDetailTypeName,
		  FinanceContactDetailTypeValue)

	SELECT	0,								-- RowStatus - tinyint
			@TargetGuid,					-- Guid - uniqueidentifier
			e.OrganisationalUnitID,			-- OrganisationalUnitID - int
			e.Date,							-- Date - datetime2(7)
			e.CreatedByUserId,				-- CreatedByUserId - int
			e.Number,							-- Number - nvarchar(50)
			e.PropertyId,					-- PropertyId - int
			e.PropertyNameNumber,			-- PropertyNameNumber - nvarchar(100)
			e.PropertyAddressLine1,			-- PropertyAddressLine1 - nvarchar(255)
			e.PropertyAddressLine2,			-- PropertyAddressLine2 - nvarchar(255)
			e.PropertyAddressLine3,			-- PropertyAddressLine3 - nvarchar(255)
			e.PropertyTown,					-- PropertyTown - nvarchar(255)
			e.PropertyCountyId,				-- PropertyCountyId - int
			e.PropertyPostCode,				-- PropertyPostCode - nvarchar(30)
			e.PropertyCountryId,			-- PropertyCountryId - int
			e.ClientAccountId,				-- ClientAccountId - int
			e.ClientAddressId,				-- ClientAddressId - int
			e.ClientAccountContactId,		-- ClientAccountContactId - int
			e.ClientName,					-- ClientName - nvarchar(250)
			e.ClientAddressNameNumber,		-- ClientAddressNameNumber - nvarchar(100)
			e.ClientAddressLine1,			-- ClientAddressLine1 - nvarchar(255)
			e.ClientAddressLine2,			-- ClientAddressLine2 - nvarchar(255)
			e.ClientAddressLine3,			-- ClientAddressLine3 - nvarchar(255)
			e.ClientAddressTown,			-- ClientAddressTown - nvarchar(255)
			e.ClientAddressCountyId,		-- ClientAddressCountyId - int
			e.ClientAddressPostCode,		-- ClientAddressPostCode - nvarchar(30)
			e.ClientAddressCountryId,		-- ClientAddressCountryId - int
			e.AgentAccountId,				-- AgentAccountId - int
			e.AgentAddressId,				-- AgentAddressId - int
			e.AgentAccountContactId,		-- AgentAccountContactId - int
			e.AgentName,					-- AgentName - nvarchar(250)
			e.AgentAddressNameNumber,		-- AgentAddressNameNumber - nvarchar(100)
			e.AgentAddressLine1,			-- AgentAddressLine1 - nvarchar(255)
			e.AgentAddressLine2,			-- AgentAddressLine2 - nvarchar(255)
			e.AgentAddressLine3,			-- AgentAddressLine3 - nvarchar(255)
			e.AgentTown,					-- AgentTown - nvarchar(255)
			e.AgentCountyId,				-- AgentCountyId - int
			e.AgentAddressPostCode,			-- AgentAddressPostCode - nvarchar(30)
			e.AgentCountryId,				-- AgentCountryId - int
			e.DescriptionOfWorks,			-- DescriptionOfWorks - nvarchar(4000)
			e.ValueOfWork,					-- ValueOfWork - decimal(19, 2)
			e.CurrentProjectRibaStageID,	-- CurrentProjectRibaStageID - int
			e.RibaStage0Months,				-- RibaStage0Months - int
			e.RibaStage1Months,				-- RibaStage1Months - int
			e.RibaStage2Months,				-- RibaStage2Months - int
			e.RibaStage3Months,				-- RibaStage3Months - int
			e.RibaStage4Months,				-- RibaStage4Months - int
			e.RibaStage5Months,				-- RibaStage5Months - int
			e.RibaStage6Months,				-- RibaStage6Months - int
			e.RibaStage7Months,				-- RibaStage7Months - int
			e.PreConstructionStageMonths,	-- PreConstructionStageMonths - int
			e.ConstructionStageMonths,		-- ConstructionStageMonths - int
			e.SendInfoToClient,				-- SendInfoToClient - bit
			e.SendInfoToAgent,				-- SendInfoToAgent - bit
			e.KeyDates,						-- KeyDates - nvarchar(2000)
			e.ExpectedProcurementRoute,		-- ExpectedProcurementRoute - nvarchar(200)
			e.Notes,						-- Notes - nvarchar(max)
			e.EnquirySourceId,				-- EnquirySourceId - int
			(1),							-- IsReadyForQuoteReview - bit
			NULL,			-- QuotingDeadlineDate - date
			NULL,			-- DeclinedToQuoteDate - date
			N'',		-- DeclinedToQuoteReason - nvarchar(4000)
			e.ExternalReference,			-- ExternalReference - nvarchar(50)
			e.ProjectId,					-- ProjectId - int
			e.IsSubjectToNDA,				-- IsSubjectToNDA - bit
			NULL,							-- DeadDate - date
			NULL,							-- ChaseDate1 - date
			NULL,							-- ChaseDate2 - date
			e.IsClientFinanceAccount,		-- IsClientFinanceAccount - bit
			e.FinanceAccountId,				-- FinanceAccountId - int
			e.FinanceAddressId,				-- FinanceAddressId - int
			e.FinanceContactId,				-- FinanceContactId - int
			e.FinanceAccountName,			-- FinanceAccountName - nvarchar(250)
			e.FinanceAddressNameNumber,		-- FinanceAddressNameNumber - nvarchar(100)
			e.FinanceAddressLine1,			-- FinanceAddressLine1 - nvarchar(255)
			e.FinanceAddressLine2,			-- FinanceAddressLine2 - nvarchar(255)
			e.FinanceAddressLine3,			-- FinanceAddressLine3 - nvarchar(255)
			e.FinanceTown,					-- FinanceTown - nvarchar(255)
			e.FinanceContactId,				-- FinanceCountyId - int
			e.FinancePostCode,				-- FinancePostCode - nvarchar(30)
			e.EnterNewClientDetails,		-- EnterNewClientDetails - bit
			e.EnterNewAgentDetails,			-- EnterNewAgentDetails - bit
			e.EnterNewFinanceDetails,		-- EnterNewFinanceDetails - bit
			e.EnterNewStructureDetails,		-- EnterNewStructureDetails - bit
			e.SignatoryIdentityId,			-- SignatoryIdentityId - int
			e.ProposalLetter,				-- ProposalLetter - nvarchar(max)
			ISNULL (   latest_revision.rev,
					   0
				   ) + 1,
			CASE
				WHEN e.OriginalEnquiryId = (-1) THEN e.ID
				ELSE e.OriginalEnquiryId
			END,
			 e.ClientContactDisplayName, --ClientContactDisplayName nvarchar(250)
			 e.ClientContactDetailType,  --ClientContactDetailType smallint
			 e.ClientContactDetailTypeName, --ClientContactDetailTypeName nvarchar(100)
			 e.ClientContactDetailTypeValue, --ClientContactDetailTypeValue nvarchar(250)
			 e.AgentContactDisplayName, --AgentContactDisplayName nvarchar(250)
			 e.AgentContactDetailType,  --AgentContactDetailType smallint
			 e.AgentContactDetailTypeName, --AgentContactDetailTypeName nvarchar(100)
			 e.AgentContactDetailTypeValue, --AgentContactDetailTypeValue nvarchar(250)
			 e.FinanceContactDisplayName, --FinanceContactDisplayName nvarchar(250)
			 e.FinanceContactDetailType, --FinanceContactDetailType smallint
			 e.FinanceContactDetailTypeName, --FinanceContactDetailTypeName nvarchar(100)
			 e.FinanceContactDetailTypeValue --FinanceContactDetailTypeValue nvarchar(250)

	FROM	SSop.Enquiries AS e
	OUTER APPLY
			(
				SELECT	MAX (q1.Revision) AS rev
				FROM	SSop.Enquiries AS q1
				WHERE	(q1.OriginalEnquiryId = CASE
												  WHEN e.OriginalEnquiryId = (-1) THEN e.ID
												  ELSE e.OriginalEnquiryId
											  END
						)
			)			AS latest_revision
	WHERE	(e.Guid = @SourceGuid);

	SELECT	@ID = SCOPE_IDENTITY ();

	-- Build the collection of Enquiry Services to duplicate. 
	DECLARE @EnquiryServices SCore.TwoGuidUniqueList;

	INSERT	@EnquiryServices
		 (GuidValue, GuidValueTwo)
	SELECT	es.Guid,
			NEWID ()
	FROM	SSop.EnquiryServices AS es
	JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
	WHERE	(e.Guid = @SourceGuid);

	-- Create the data objects. 
	DECLARE @NewGuidList SCore.GuidUniqueList;

	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@EnquiryServices;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,			-- GuidUniqueList
									@SchemeName = N'SSop',				-- nvarchar(255)
									@ObjectName = N'EnquiryServices',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;		-- bit

	DELETE	FROM @NewGuidList;

	INSERT	SSop.EnquiryServices
		 (RowStatus, Guid, EnquiryId, JobTypeId, StartRibaStageId, EndRibaStageId, QuoteId)
	SELECT	1,
			es.GuidValueTwo,
			@ID,
			es2.JobTypeId,
			es2.StartRibaStageId,
			es2.EndRibaStageId,
			-1
	FROM	@EnquiryServices	 AS es
	JOIN	SSop.EnquiryServices AS es2 ON (es.GuidValue = es2.Guid);

	DECLARE @ServiceQuoteList AS SCore.ThreeGuidUniqueList,
			@CurrentQuote	  UNIQUEIDENTIFIER,
			@NewQuoteGuid	  UNIQUEIDENTIFIER,
			@MaxQuote		  UNIQUEIDENTIFIER;

	INSERT	@ServiceQuoteList
		 (GuidValue, GuidValueTwo, GuidValueThree)
	SELECT	q.Guid,
			NEWID (),
			es2.GuidValueTwo
	FROM	SSop.Quotes			 AS q
	JOIN	SSop.EnquiryServices AS es ON (es.ID	= q.EnquiryServiceID)
	JOIN	@EnquiryServices	 AS es2 ON (es.Guid = es2.GuidValue);


	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@EnquiryServices;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,			-- GuidUniqueList
									@SchemeName = N'SSop',				-- nvarchar(255)
									@ObjectName = N'EnquiryServices',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;		-- bit	

	DELETE	FROM @NewGuidList;

	SELECT	@MaxQuote	  = MAX (tgul.GuidValue),
			@CurrentQuote = '00000000-0000-0000-0000-000000000000'
	FROM	@ServiceQuoteList AS tgul;

	WHILE @CurrentQuote < @MaxQuote
	BEGIN
		SELECT		@CurrentQuote = GuidValue,
					@NewQuoteGuid = GuidValueTwo
		FROM		@ServiceQuoteList
		WHERE		(GuidValue > @CurrentQuote)
		ORDER BY	GuidValue;

		EXEC SSop.QuotesRevise @SourceGuid = @CurrentQuote,	-- uniqueidentifier
								  @TargetGuid = @NewQuoteGuid;	-- uniqueidentifier

		UPDATE	q
		SET		q.EnquiryServiceID = es.ID
		FROM	SSop.Quotes			 AS q
		JOIN	@ServiceQuoteList	 AS ql ON (q.Guid  = ql.GuidValueTwo)
		JOIN	SSop.EnquiryServices AS es ON (es.Guid = ql.GuidValueThree);

	END;


	-- Allocate a new Enquiry number. 

	UPDATE	SSop.Enquiries
	SET		RowStatus = 1
	WHERE	(ID = @ID);
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

