--
-- Create or alter function [SFin].[tvf_InvoiceRequests]
--
GO
CREATE OR ALTER FUNCTION [SFin].[tvf_InvoiceRequests]
	(
		@UserId INT
	)
RETURNS TABLE
--WITH SCHEMABINDING
AS
RETURN SELECT		ir.ID,
					ir.RowStatus,
					ir.RowVersion,
					ir.Guid,
					ir.Notes,
					ir.CreatedDateTimeUTC,
					i.Guid					  AS RequesterUserId,
					i.FullName				  AS SurveyorName,
					j.Guid					  AS JobId,
					j.Number,
					j.FinanceAccountID,
																		-- [CBLD-522]
					STRING_AGG (   ActT.Name,
								   ', '
							   )			  AS ActivityID,			-- Activity name
																		-- [CBLD-525]
					Acc.Name				  AS ClientName,			-- Client the request is associated with
					SUM (IRI.Net)			  AS Net,					-- Invoice Request Amount
					MAX (Act.EndDate)		  AS EndDate,				-- On or prior to today's date
					j.BillingInstruction	  AS JobBillingInstruction, -- Job billing instruction
					FinAcc.BillingInstruction AS CRMBillingInstruction, -- CRM billing instruction
					CASE
						WHEN MAX (	 CASE
										 WHEN ActT.IsBillable = 0 THEN 'No'
										 ELSE 'Yes'
									 END
								 ) = 'Yes' THEN 'Yes'
						ELSE 'No'
					END						  AS IsBillable
	   FROM			SFin.InvoiceRequests	 AS ir
	   JOIN			SJob.Jobs				 AS j ON (j.ID					 = ir.JobId)
	   JOIN			SCore.Identities		 AS i ON (i.ID					 = ir.RequesterUserId)
	   INNER JOIN	SFin.InvoiceRequestItems AS IRI ON (IRI.InvoiceRequestId = ir.ID) -- NEW => [CBLD-522]
	   INNER JOIN	SJob.Activities			 AS Act ON (IRI.ActivityId		 = Act.ID) -- NEW => [CBLD-522]
	   INNER JOIN	SJob.ActivityTypes		 AS ActT ON (Act.ActivityTypeID	 = ActT.ID) -- NEW => [CBLD-522]
	   INNER JOIN	SCrm.Accounts			 AS Acc ON (Acc.ID				 = j.ClientAccountID) -- NEW => [CBLD-525]
	   LEFT JOIN	SCrm.Accounts			 AS FinAcc ON (FinAcc.ID		 = j.FinanceAccountID)
	   WHERE		(ir.RowStatus NOT IN (0, 254))
				AND (ir.ID			  > 0)
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SFin.InvoiceRequestItems AS iri
			   WHERE	(iri.RowStatus NOT IN (0, 254))
					AND (iri.InvoiceRequestId = ir.ID)
		   )
					)
				-- [CBLD-524] Completed Activity
				AND
				  (
					  (EXISTS
		   (
			   SELECT		1
			   FROM			SFin.InvoiceRequestItems AS iri
			   INNER JOIN	SJob.Activities			 AS act ON (iri.ActivityId = act.ID)
			   WHERE		(
								act.ActivityStatusID = 3
							 OR act.ID				 < 0
							)
						AND (iri.InvoiceRequestId	 = ir.ID)  -- Always connect back to main query
		   )
					  )
				   OR (IRI.ActivityId < 0)
				  )
				-- [CBLD-524] Activity must have an associated value
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SFin.InvoiceRequestItems AS iri
			   WHERE	(iri.RowStatus NOT IN (0, 254))
					AND (iri.Net			  > 0.00)
					AND (iri.InvoiceRequestId = ir.ID)	-- Always connect back to main query
		   )
					)
				-- [CBLD-524] Activity is on or prior to today's date 
				AND
				  (
					  (EXISTS
		   (
			   SELECT		1
			   FROM			SFin.InvoiceRequestItems AS iri
			   INNER JOIN	SJob.Activities			 AS Act ON (iri.ActivityId = Act.ID)
			   WHERE		(iri.RowStatus NOT IN (0, 254))
						AND (CAST (Act.EndDate AS DATE) <= CAST (GETDATE () AS DATE))
						AND (iri.InvoiceRequestId		= ir.ID)  -- Always connect back to main query
		   )
					  )
				   OR (IRI.ActivityId < 0)
				  )
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
					)
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	ir.Guid,
																@UserId
															) AS oscr
		   )
					)
				AND (NOT EXISTS
		   (
			   SELECT		1
			   FROM			SFin.TransactionDetails	 AS td
			   INNER JOIN	SFin.InvoiceRequestItems AS iri ON (iri.ID = td.InvoiceRequestItemId)
			   WHERE		(iri.InvoiceRequestId = ir.ID)
		   )
					)
	   GROUP BY		ir.ID,
					ir.RowStatus,
					ir.RowVersion,
					ir.Guid,
					ir.Notes,
					ir.CreatedDateTimeUTC,
					i.Guid,
					i.FullName,
					j.Guid,
					j.Number,
					j.FinanceAccountID,
					ActT.Name,
					Acc.Name,
					j.BillingInstruction,
					FinAcc.BillingInstruction;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_DataPills]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_DataPills]
  (
    @Guid                      UNIQUEIDENTIFIER,
    @AppFormReceived           BIT,
    @ClientAppointmentReceived BIT,
    @ClientAccountGuid         UNIQUEIDENTIFIER,
    @AgentAccountGuid          UNIQUEIDENTIFIER,
	@FinanceAccountGuid		   UNIQUEIDENTIFIER, 
    @JobCompleted              DATETIME2,
    @JobCancelled              DATETIME2,
    @JobDormant                DATETIME2,
    @JobStarted                DATETIME2,
	@OrganisationalUnitGuid    UNIQUEIDENTIFIER, 
	@IsNDA					   BIT 
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
    DECLARE @JobID INT

    SELECT
            @JobID = ID
    FROM
            SJob.Jobs
    WHERE
            (Guid = @Guid)

  
  --CBLD-680
  IF(@IsNDA = 1 )
	BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'NDA',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
    END



    -- Complete Job
    IF (@JobCompleted IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Complete',	-- Label - nvarchar(50)
                  N'bg-success',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Cancelled Job
    IF (@JobCancelled IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Cancelled',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END


    -- Dormant Job
    IF (@JobDormant IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Dormant',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Started Job
    IF (@JobStarted IS NOT NULL)
      AND
      (@JobCompleted IS NULL)
      AND
      (@JobCancelled IS NULL)
      AND
      (@JobDormant IS NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Started',	-- Label - nvarchar(50)
                  N'bg-info',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Client Account on hold
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SCrm.Accounts a
          JOIN
                  SCrm.AccountStatus st ON (st.ID = a.AccountStatusID)
          WHERE
                  (a.Guid = @ClientAccountGuid)
                  AND (st.IsHold = 1)
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Client Account Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END

    -- Agent account on hold
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SCrm.Accounts a
          JOIN
                  SCrm.AccountStatus st ON (st.ID = a.AccountStatusID)
          WHERE
                  (a.Guid = @AgentAccountGuid)
                  AND (st.IsHold = 1)
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Agent Account Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END
	  -- Finance Account On Credit Hold
	  IF (EXISTS
			(
				SELECT 
						1
				FROM 
						SCrm.Accounts Ac
				WHERE Ac.Guid = @FinanceAccountGuid AND Ac.AccountStatusID = 4
			)	
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Credit Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END


    -- Outstanding Fees
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SFin.Transactions t
          JOIN
                  SFin.TransactionCalculations tc ON (tc.ID = t.ID)
          JOIN
                  SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
          WHERE
                  (t.JobID = @JobID)
                  AND (tc.RealOutstanding <> 0)
                  AND (tt.IsBank = 0)
                  AND (tc.DueDate < GETDATE())
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Overdue Invoices',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END


    -- App Form not received
    IF (@AppFormReceived = 0)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'App Form Not Received',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  4		-- SortOrder - int
                )
      END

	  --Outstanding Actions
	  	  IF(EXISTS
		(
			SELECT 
				1
			FROM SJob.Actions AS a
			WHERE a.RowStatus NOT IN (0, 254)
			AND a.ActionStatusId <> 1
			  AND (
					EXISTS (
						SELECT 1
						FROM SJob.Jobs AS j
						WHERE j.Guid = @Guid
						  AND j.ID = a.JobID
			 
					)
				 OR EXISTS (
						SELECT 1
						FROM SJob.Milestones AS m
						JOIN SJob.Jobs AS jm ON (jm.ID = m.JobID)
						WHERE jm.Guid = @Guid
						  AND a.MilestoneID = m.ID
						  AND m.RowStatus NOT IN (0, 254)
					)
				 OR EXISTS (
						SELECT 1
						FROM SJob.Activities AS act
						WHERE a.ActivityID = act.ID
						  AND act.RowStatus NOT IN (0, 254)
						  AND (
								EXISTS (
									SELECT 1
									FROM SJob.Jobs AS jact
									WHERE jact.Guid = @Guid
									  AND jact.ID = act.JobID
								)
							 OR EXISTS (
									SELECT 1
									FROM SJob.Milestones AS am
									JOIN SJob.Jobs AS amj ON (amj.ID = am.JobID)
									WHERE amj.Guid = @Guid
									  AND act.MilestoneID = am.ID
									  AND am.RowStatus NOT IN (0, 254)
								)
							)
					)
	
			)
		)
	  )
	  BEGIN
		INSERT @DataPills
		(Label,
		 Class,
		 SortOrder	
		)
		VALUES
		(
		 N'Outstanding Actions',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  4		-- SortOrder - int
		)
	  END


    -- No Written Appointment
    /*IF (EXISTS 
  			(
  				SELECT	1
  				FROM	SJob.Milestones m 
  				JOIN	SJob.MilestoneTypes mt ON (mt.ID = m.MilestoneTypeID)
  				WHERE	(m.JobID = @JobID)
  					AND	(mt.Code = N'WAR')
  					AND	(m.CompletedDateTimeUTC IS NULL)
  					AND	(m.IsNotApplicable = 0)
  			)
  		)
  	BEGIN 
  		INSERT @DataPills
  			(
  				Label, Class, SortOrder
  			)
  		VALUES(
  				  N'No Written Appointment',	-- Label - nvarchar(50)
  				  N'bg-danger',	-- Class - nvarchar(50)
  				  5		-- SortOrder - int
  			  )
  	END*/


	--Create a table of org units - bccs jobs should not show org i
	DECLARE @OrgTypes TABLE (OrganisationalUnitID UNIQUEIDENTIFIER);
	INSERT INTO @OrgTypes (OrganisationalUnitID)
	VALUES ('F233BB03-3181-49AE-B331-39C58F328457'); --BCCS

    IF (@ClientAppointmentReceived = 0 AND  @OrganisationalUnitGuid NOT IN (SELECT OrganisationalUnitID FROM @OrgTypes))
	AND	(EXISTS 
	(
		SELECT	1 
		FROM	SJob.JobTypes AS jt 
		JOIN	SJob.Jobs AS j ON (j.JobTypeID = jt.ID)
		WHERE (jt.Name IN (N'CDM PD', N'CDM PD (Construction Phase Only)', N'CDM PD (Pre-Construction Phase Only)'))
	)
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'No Client Appointment Received',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  5		-- SortOrder - int
                )
      END

    -- F10 Expired
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SJob.Milestones m
          JOIN
                  SJob.MilestoneTypes mt ON (mt.ID = m.MilestoneTypeID)
          WHERE
                  (m.JobID = @JobID)
                  AND (mt.Code = N'F10')
                  AND (m.CompletedDateTimeUTC IS NULL)
                  AND (m.IsNotApplicable = 0)
                  AND (
                          (CONVERT(DATE, ISNULL(m.DueDateTimeUTC, GETUTCDATE())) < CONVERT(DATE, GETUTCDATE()))
                          OR (CONVERT(DATE, ISNULL(m.ScheduledDateTimeUTC, GETUTCDATE())) < CONVERT(DATE, GETUTCDATE()))
                  )
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'F10 Expired',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  6		-- SortOrder - int
                )
      END

	  -- MileStones Past Deadline Date
	  IF (EXISTS
			(
				SELECT	1
				FROM	SJob.Milestones m
				WHERE	(m.JobId = @JobID)
					AND	(m.CompletedDateTimeUTC IS NULL)
					AND	(ISNULL(m.DueDateTimeUTC, GETUTCDATE()) < GETUTCDATE())
			)
		)
		BEGIN 
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Overdue Milestones.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						6		-- SortOrder - int
					)
		END


	  -- Incomplete historic activities 
	  IF	(EXISTS
				(
					SELECT	1
					FROM	SJob.Activities a
					WHERE	(a.JobID = @JobID)
						AND	(a.EndDate < GETUTCDATE())
						AND	(EXISTS
								(
									SELECT	1
									FROM	SJob.ActivityStatus ast
									WHERE	(ast.ID = a.ActivityStatusID)
										AND	(ast.IsCompleteStatus = 0) 
								)
							)
				)	
			)
		BEGIN 
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Incomplete Activities.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						6		-- SortOrder - int
					)
		END

    RETURN
  END


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SJob].[Jobs_DWETL]
--
GO
CREATE OR ALTER VIEW [SJob].[Jobs_DWETL]
	        --WITH SCHEMABINDING
AS
SELECT	j.ID,
		j.OrganisationalUnitID,
		ou.Name AS OUName,
		j.ClientAccountID,
		j.AgentAccountID,
		j.SurveyorID,
		ISNULL(jf.InvoicedValue, 0) InvoicedValue,
		jt.Name AS JobType,
		CONVERT(DATE, j.JobStarted) RegisteredDate,
		CONVERT(DATE, j.JobCompleted) CompletedDate,
		j.AgreedFee + j.RibaStage1Fee + j.RibaStage2Fee + j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.ConstructionStageFee + j.PreConstructionStageFee AS OriginalQuotedValue,
		j.AgreedFee + j.RibaStage1Fee + j.RibaStage2Fee + j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.ConstructionStageFee + j.PreConstructionStageFee + ISNULL(FeeAmendment.Total, 0) AS ActualQuotedValue,
		PhysicalInspections.Cnt AS PhysicalInspections,
		TotalInspections.Cnt AS TotalInspections,
		j.Number,
		c.Name AS County,
		p.Postcode
FROM	SJob.Jobs j
JOIN	SJob.JobStatus js ON (js.ID = j.ID)
JOIN	SJob.JobFinance jf ON (jf.ID = j.ID)
JOIN	SCore.Identities i ON (i.ID = j.SurveyorID)
JOIN	SJob.JobTypes jt ON (jt.ID = j.JobTypeID)
JOIN	SJob.Assets AS p ON (p.ID = j.UprnID)
JOIN	SCrm.Counties AS c ON (c.ID = p.CountyId)
JOIN	SCore.OrganisationalUnits AS ou ON (ou.ID = j.OrganisationalUnitID)
OUTER APPLY	
(
	SELECT	COUNT(1) AS Cnt
	FROM	SJob.Activities a
	JOIN	SJob.ActivityStatus stat ON (stat.ID = a.ActivityStatusID)
	JOIN	SJob.ActivityTypes atype ON (atype.ID = a.ActivityTypeID)
	WHERE	(j.id = a.JobID)
		AND	(stat.Name = N'Complete')
		AND	(atype.IsSiteVisit = 1)
		AND	(a.RowStatus NOT IN (0, 254))
) AS PhysicalInspections
OUTER APPLY	
(
	SELECT	COUNT(1) AS Cnt
	FROM	SJob.Activities a
	JOIN	SJob.ActivityStatus stat ON (stat.ID = a.ActivityStatusID)
	JOIN	SJob.ActivityTypes atype ON (atype.ID = a.ActivityTypeID)
	WHERE	(j.id = a.JobID)
		AND	(stat.Name = N'Complete')
		AND	(a.RowStatus NOT IN (0, 254))
) AS TotalInspections
OUTER APPLY	
(
	SELECT	SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change + fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.ConstructionStageChange + fa.PreConstructionStageChange) AS Total
	FROM	SJob.FeeAmendment fa
	WHERE	(fa.JobID = j.Id)
		AND	(fa.RowStatus NOT IN (0, 254))
) AS FeeAmendment
WHERE	(j.JobCancelled IS NULL)
	AND	(
			(EXISTS
				(
					SELECT	1
					FROM	SCore.RecordHistory rh
					WHERE	(rh.RowGuid = j.Guid)
						AND	(rh.Datetime > DATEADD(MONTH, -6, GETDATE()))
				)
			)
			OR
			(EXISTS
				(
					SELECT	1
					FROM	SCore.RecordHistory rh
					WHERE	(rh.Datetime > DATEADD(MONTH, -6, GETDATE()))
						AND	(EXISTS
								(
									SELECT	1
									FROM	SJob.Activities a
									WHERE	(a.JobID = j.ID)
										AND	(a.Guid = rh.RowGuid)
								)
							)
				)
			)
			OR
			(EXISTS
				(
					SELECT	1
					FROM	SCore.RecordHistory rh
					WHERE	(rh.Datetime > DATEADD(MONTH, -6, GETDATE()))
						AND	(EXISTS
								(
									SELECT	1
									FROM	SFin.Transactions t
									WHERE	(t.JobID = j.ID)
										AND	(t.Guid = rh.RowGuid)
								)
							)
				)
			)
		)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_AssetMergeBatchValidate]
--
GO



CREATE OR ALTER FUNCTION [SJob].[tvf_AssetMergeBatchValidate]
	(
		@SourceAssetGuid UNIQUEIDENTIFIER,
		@TargetAssetGuid UNIQUEIDENTIFIER,
		@CreatedByUserGuid UNIQUEIDENTIFIER,
		@CheckedByUserGuid UNIQUEIDENTIFIER,
		@IsComplete BIT,
		@Guid UNIQUEIDENTIFIER
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		[IsInformationOnly] [BIT] NOT NULL DEFAULT((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER,
			@EntityTypeGuid UNIQUEIDENTIFIER,
			@CurrentUserGuid UNIQUEIDENTIFIER = SCore.GetCurrentUserGuid()

	SELECT	@EntityTypeGuid = et.Guid
	FROM	SCore.EntityTypes AS et
	WHERE	(et.Name = N'Asset Merge Batch')

	IF (@IsComplete = 1)
	BEGIN 
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityTypeGuid,
				 N'E',
				 1,
				 0,
				 0,
				 N''
			 );

		RETURN	
	END

	IF (@CreatedByUserGuid = @CurrentUserGuid)
	BEGIN 
		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'CheckedByUserId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 1,
				 0,
				 0,
				 N''
			 );
	END
	
	IF (@CreatedByUserGuid = @CheckedByUserGuid)
	BEGIN 
		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'CheckedByUserId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 0,
				 0,
				 1,
				 N'A different user must check the merge.'
			 );
	END
	
	IF (@TargetAssetGuid = @SourceAssetGuid)
	AND	(@SourceAssetGuid <> '00000000-0000-0000-0000-000000000000')
	BEGIN 
		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'SourceAssetId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 0,
				 0,
				 1,
				 N'The Source and Target Asset must be different.'
			 );

		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'TargetAssetId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 0,
				 0,
				 1,
				 N'The Source and Target Asset must be different.'
			 );
	END

	IF (EXISTS 
			(
				SELECT	1
				FROM	SCrm.AccountMergeBatch
				WHERE	(IsComplete = 1)
					AND	(Guid = @Guid)
			)
		)
	BEGIN 
		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'TargetAssetId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 1,
				 0,
				 1,
				 N''
			 );

		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'SourceAssetId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 1,
				 0,
				 1,
				 N''
			 );

		SELECT @EntityPropertyGuid = SCore.GetEntityPropertyGuid(N'SJob', N'AssetMergeBatch', N'CheckedByUserId')

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 1,
				 0,
				 1,
				 N''
			 );
	END
	
	RETURN;
END;

GO
